import torch
import torch.utils.checkpoint as checkpoint

class CheckpointedBlock(nn.Module):
    def __init__(self, module):
        super().__init__()
        self.module = module

    def forward(self, x):
        return checkpoint.checkpoint(self.module, x)

block = CheckpointedBlock(nn.Linear(10, 10))
x = torch.randn(1, 10)
out = block(x)
print(f"Checkpointed block output shape: {out.shape}")

import torch
import torch.nn as nn

class CustomModel(nn.Module):
    def __init__(self):
        super().__init__()
        self.add_module('linear1', nn.Linear(10, 5))
        self.add_module('linear2', nn.Linear(5, 2))

    def forward(self, x):
        return self.linear2(torch.relu(self.linear1(x)))

model = CustomModel()
print("Layers via named_children:")
for name, layer in model.named_children():
    print(f"  {name}: {layer}")

